import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [view, setView] = useState("tables");
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [toast, setToast] = useState(null);

  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 2000);
  };

  const loadData = useCallback(async () => {
    try {
      const [t, m] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
      ]);
      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const selectTable = async (table) => {
    setSelectedTable(table);
    setView("order");
    setAllRounds([]);
  };

  const startOrder = async () => {
    const res = await API.post("/orders", { table_id: selectedTable.id });
    setAllRounds([{ order: res.data, items: [] }]);
    setDraftRoundIdx(0);
  };

  const addItem = async (item) => {
    const round = allRounds[draftRoundIdx];
    await API.post(`/orders/${round.order.id}/items`, {
      menu_id: item.id,
      quantity: 1,
      unit_price: item.price
    });
    showToast(`Added ${item.name}`);
  };

  const sendToKitchen = async () => {
    const round = allRounds[draftRoundIdx];
    await API.put(`/orders/${round.order.id}/confirm`);
    showToast("Sent to kitchen 🚀");
    setDraftRoundIdx(null);
  };

  const goBack = () => {
    setView("tables");
    setSelectedTable(null);
    setAllRounds([]);
  };

  return (
    <div style={{ minHeight: "100vh", background: "#0f172a", color: "#fff" }}>

      {/* HEADER */}
      <header style={{
        padding: "16px 24px",
        display: "flex",
        justifyContent: "space-between",
        borderBottom: "1px solid #1f2937"
      }}>
        <div>
          <div style={{ fontWeight: 700 }}>Waiter Panel</div>
          <div style={{ fontSize: 12, color: "#9ca3af" }}>
            {user?.restaurant_name}
          </div>
        </div>

        <button onClick={() => { logout(); navigate("/"); }}>
          Logout
        </button>
      </header>

      <div style={{ padding: 20 }}>

        {/* TABLE VIEW */}
        {view === "tables" && (
          <div className="table-grid">
            {tables.map(t => (
              <div
                key={t.id}
                onClick={() => selectTable(t)}
                style={{
                  background: "#111827",
                  padding: 20,
                  borderRadius: 16,
                  cursor: "pointer",
                  transition: "0.2s",
                  boxShadow: "0 4px 20px rgba(0,0,0,0.3)"
                }}
                onMouseEnter={e => e.currentTarget.style.transform = "scale(1.05)"}
                onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
              >
                <div style={{ fontSize: 18, fontWeight: 700 }}>
                  Table {t.table_number}
                </div>
                <div style={{ fontSize: 12, color: "#9ca3af" }}>
                  {t.status}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ORDER VIEW */}
        {view === "order" && (
          <div style={{ display: "grid", gridTemplateColumns: "1fr 350px", gap: 20 }}>

            {/* MENU */}
            <div>
              <button onClick={goBack}>← Back</button>

              {allRounds.length === 0 && (
                <button onClick={startOrder}>Start Order</button>
              )}

              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))",
                gap: 12,
                marginTop: 20
              }}>
                {menu.map(item => (
                  <div
                    key={item.id}
                    onClick={() => addItem(item)}
                    style={{
                      background: "#111827",
                      padding: 14,
                      borderRadius: 12,
                      cursor: "pointer",
                      transition: "0.2s"
                    }}
                    onMouseDown={e => e.currentTarget.style.transform = "scale(0.95)"}
                    onMouseUp={e => e.currentTarget.style.transform = "scale(1)"}
                  >
                    <div>{item.name}</div>
                    <div style={{ color: "#10b981" }}>
                      Rs. {item.price}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* SUMMARY */}
            <div style={{
              background: "#111827",
              borderRadius: 16,
              padding: 16,
              height: "fit-content",
              position: "sticky",
              top: 20
            }}>
              <h3>Order Summary</h3>

              {allRounds.map((r, idx) => (
                <div key={idx}>
                  <div>Round {idx + 1}</div>
                </div>
              ))}

              {draftRoundIdx !== null && (
                <button
                  onClick={sendToKitchen}
                  style={{
                    width: "100%",
                    marginTop: 20,
                    background: "#6366f1",
                    padding: 12,
                    borderRadius: 10,
                    fontWeight: 700
                  }}
                >
                  Send to Kitchen
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {/* TOAST */}
      {toast && (
        <div style={{
          position: "fixed",
          bottom: 20,
          left: "50%",
          transform: "translateX(-50%)",
          background: "#1f2937",
          padding: "10px 20px",
          borderRadius: 10
        }}>
          {toast}
        </div>
      )}
    </div>
  );
}
